class Solution:
    def minWindow(self, s: str, t: str) -> str:

        total = 0
        mp = {}
        for c in t:
            if c not in mp:
                mp[c] = 1
                total += 1
            else:
                mp[c] += 1
        
        l = 0
        ret = ""

        for r in range(len(s)):

            if s[r] in mp:
                mp[s[r]] -= 1
                if mp[s[r]] == 0:
                    total -= 1

            while total == 0:
                if len(ret) > len(s[l:r + 1]):
                    ret = s[l:r + 1]
                if s[l] in mp:
                    mp[s[l]] += 1
                    if mp[s[l]] > 0:
                        total += 1
                l += 1
            print(s[l:r+1])
        
        if ret == "":
            return ""
        else:
            return ret


